import{_ as d,o as r,c as a,a7 as e}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"深海界域（Aequor）","description":"","frontmatter":{},"headers":[],"relativePath":"realms/aequor.md","filePath":"zh/realms/aequor.md","lastUpdated":1775394001000}'),o={name:"realms/aequor.md"};function l(s,t,i,n,h,u){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="深海界域-aequor" tabindex="-1">深海界域（Aequor） <a class="header-anchor" href="#深海界域-aequor" aria-label="Permalink to &quot;深海界域（Aequor）&quot;">​</a></h1><p><span class="realm-badge realm-aequor">深海 Aequor</span></p><h2 id="界域特性" tabindex="-1">界域特性 <a class="header-anchor" href="#界域特性" aria-label="Permalink to &quot;界域特性&quot;">​</a></h2><p>深海界域以<strong>触腕系统</strong>为核心机制，通过在回合结束时自动攻击造成持续伤害。v2.4版本界域强度评级为 <strong>S级</strong>，增强后为当前最强界域。</p><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><ul><li><strong>触腕系统</strong> — 战斗开始时生成1条触腕，深海唤醒体打出部分卡牌时除狂气值外额外获得触腕，触腕在回合结束时对前排敌人进行攻击。每次释放爆发后驱使触腕进行1次攻击</li><li><strong>至纯深海</strong> — 纯深海编成时，深海精通属性效果2倍，战斗开始时自动生成的触腕数量也变为2倍</li><li><strong>触手暴击</strong> — 触手的暴击率和暴击伤害为4只出战角色均分</li><li><strong>伤害公式</strong> — 力量:触手伤害=2:1；界域精通:狂气爆发后触手追加攻击次数=2:1</li></ul><h2 id="深海界域唤醒体" tabindex="-1">深海界域唤醒体 <a class="header-anchor" href="#深海界域唤醒体" aria-label="Permalink to &quot;深海界域唤醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th>唤醒体</th><th>定位</th><th>Tier</th><th>获取方式</th></tr></thead><tbody><tr><td>图鲁 (Tulu)</td><td>输出</td><td>T0</td><td>限定活动唤醒</td></tr><tr><td>神王·图鲁 (Divine King Tulu)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>希莱斯特 (Celeste)</td><td>辅助</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>戈利亚 (Goliath)</td><td>防御</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>珊 (Shan)</td><td>副输出</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>奥瑞塔 (Aurita)</td><td>输出</td><td>T2</td><td>免费获取(通关混沌界域裂隙I)</td></tr><tr><td>凯刻斯 (Caecus)</td><td>副输出</td><td>T2</td><td>常驻/活动唤醒</td></tr><tr><td>法洛思 (Faros)</td><td>辅助</td><td>T3</td><td>常驻/活动唤醒</td></tr><tr><td>弥利亚姆 (Miryam)</td><td>辅助</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>墨菲 (Murphy)</td><td>防御</td><td>—</td><td>唤醒</td></tr><tr><td>克珀珊特 (Corposant)</td><td>防御</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>皮克曼 (Pickman)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>诞妄·墨菲 (Murphy: Fauxborn)</td><td>合唱</td><td>—</td><td>限定活动唤醒</td></tr></tbody></table><h2 id="构筑建议" tabindex="-1">构筑建议 <a class="header-anchor" href="#构筑建议" aria-label="Permalink to &quot;构筑建议&quot;">​</a></h2><ol><li><strong>触手混伤队</strong> — 弥利亚姆+奥瑞塔+凯刻斯+墨菲（经典深海首选，攻防兼备）</li><li><strong>深海双C队</strong> — 图鲁+奥瑞塔+希莱斯特+珊（刷本速度快）</li><li><strong>凯刻斯反击队</strong> — 凯刻斯+哈姆林+戈利亚+拉蒙娜（顶配「凯狗哈环」，需高练度）</li><li><strong>鲨凯队</strong> — 戈利亚+凯刻斯+希莱斯特+珊（全常驻角色，适合新手长期投资）</li></ol><div class="tip custom-block"><p class="custom-block-title">新手建议</p><p>深海最明显的特点是回合结束自动追击，知道这一点之后就可以补刀收割。深海是开荒最舒服的队伍。仅需凯刻斯、法洛思、奥瑞塔、希莱斯特4张SR即可通关全主线。</p></div>',11)])])}const g=d(o,[["render",l]]);export{p as __pageData,g as default};
